#!/bin/sh
set -ex

# Source VM environment config if available (generated by entrypoint.sh)
[ -f /tmp/vmconfig/vm.d/05-vm-env.conf ] && . /tmp/vmconfig/vm.d/05-vm-env.conf

LAN_IP="${OPENWRT_VM_LAN_IP:-192.168.115.254}"
WAN_IP="${OPENWRT_VM_WAN_IP:-10.0.0.2}"
WAN_NETMASK="${OPENWRT_VM_WAN_NETMASK:-255.255.255.248}"

# Assign IP to LAN bridge (br-lan)
uci set network.lan.ifname='br-lan'
uci set network.lan.proto='static'
uci set network.lan.ipaddr="$LAN_IP"
uci set network.lan.netmask='255.255.255.0'

# Assign IP to WAN interface (eth1)
uci set network.wan.ifname='eth1'
uci set network.wan.proto='static'
uci set network.wan.ipaddr="$WAN_IP"
uci set network.wan.netmask="$WAN_NETMASK"

# Add default gateway via 10.0.0.1
uci set network.wan.gateway='10.0.0.1'

uci commit network
/etc/init.d/network restart
